```python
import json

def safe_divide(a, b):
    """
    This function takes two arguments, a and b, and returns a dictionary containing the result of the division operation.
    If the division results in a zero, it returns a dictionary with a key 'error' and a value 'ZeroDivisionError'.

    Example:
    >>> safe_divide(10, 2)
    {'result': 5, 'error': 'ZeroDivisionError'}
    >>> safe_divide(10, 0)
    {'error': 'ZeroDivisionError'}
    """
    try:
        return {'result': a / b}
    except ZeroDivisionError as e:
        return {'error': str(e)}

